import bisect

N, S, R = map(int, input().split())
A = list(map(int, input().split()))

prefix = [0] * (N + 1)
for i in range(1, N + 1):
    prefix[i] = prefix[i - 1] + A[i - 1]

def find_first(index, value):
    lo, hi = 0, index
    while lo < hi:
        mid = (lo + hi + 1) // 2
        if prefix[mid] < value:
            lo = mid
        else:
            hi = mid - 1
    return lo + 1

def find_last(index, value):
    lo, hi = index, N
    while lo < hi:
        mid = (lo + hi) // 2
        if prefix[mid] > value:
            hi = mid
        else:
            lo = mid + 1
    return lo - 1

ans = 0
for i in range(N):
    lo = bisect.bisect_left(A, A[i] - R)
    hi = bisect.bisect_right(A, A[i] + R)
    for j in range(lo, hi + 1):
        left = find_first(i, prefix[j] - S)
        right = find_last(i, prefix[j] - S)
        ans += max(0, right - left + 1)

print(ans)
